  // === GIFT-PACKAGING ===
  'luxury-magnetic-gift-box': { name: 'Caixa Presente Magnética de Luxo', closure: 'Magnética', tagline: 'Fecho magnético oculto para embalagem retail premium', intro: 'Uma caixa presente premium com ímanes neodímio ocultos na tampa. Exterior o mais limpo possível com sensação satisfatória de fecho snap — ideal para cosmética, relógios e embalagem retail de alta gama onde a experiência de unboxing conta.' },
  'hinged-wooden-gift-box': { name: 'Caixa Presente Madeira com Dobradiça', closure: 'Com Dobradiça', tagline: 'Maciço com dobradiças e fecho em latão', intro: 'Uma clássica caixa presente em madeira com dobradiça em pinho ou paulownia maciço. Dobradiças acabamento latão e fecho gancho dão-lhe a sensação substancial e reutilizável que torna a embalagem parte do presente.' },
  'sliding-lid-gift-box': { name: 'Caixa Presente Tampa Deslizante', closure: 'Deslizante', tagline: 'Sem ferragens com ranhuras CNC', intro: 'Uma caixa madeira sem ferragens com tampa deslizante ranhurada de precisão. Look o mais limpo possível — só madeira, com tampa que desliza suave e funciona como grande tela para branding. Perfeito para kits hobby, seleções de chá e conjuntos de canetas.' },
  'drawer-wooden-gift-box': { name: 'Caixa Presente Madeira com Gaveta', closure: 'Gaveta', tagline: 'Gaveta extraível para apresentações alta gama', intro: 'Uma caixa presente estilo gaveta que se extrai suavemente para revelar o conteúdo. Combina a sensação substancial de uma caixa com dobradiça com a surpresa de uma gaveta apresentação. Configurações um ou multi piso disponíveis.' },
  'liftoff-lid-gift-box': { name: 'Caixa Presente com Tampa Removível', closure: 'Removível', tagline: 'Construção simples em duas peças, clássica e limpa', intro: 'Uma caixa tradicional com tampa removível — um topo separado que se levanta limpo. O formato caixa presente mais simples e limpo, com tampa plana generosa para branding. Ideal para cosmética, kits hobby e qualquer aplicação que prefira abertura de "revelação".' },

  // === WATCH-JEWELRY ===
  'luxury-velvet-ring-box': { name: 'Caixa Anel Veludo Luxo', closure: 'Com Dobradiça', tagline: 'Caixa madeira maciça com interior veludo para anéis', intro: 'Uma caixa anel premium em madeira maciça com interior totalmente forrado em veludo. Dobradiça oculta e fecho magnético; o slot anel é calibrado para segurar peças pequenas sem marcar o metal. A caixa de pedido ou apresentação perfeita.' },
