  'multi-tier-earring-chest': { name: 'Cómoda Brincos Multi Piso', closure: 'Gaveta', tagline: 'Cómoda madeira com várias gavetas para joalharia', intro: 'Uma cómoda em madeira com várias gavetas forradas veludo e compartimento superior com espelho. Cada gaveta é dimensionada para tipos específicos de joalharia: brincos, anéis, pulseiras ou colares. Acabamento para anos de uso sobre toucador.' },
  'pearl-necklace-presentation-box': { name: 'Caixa Apresentação Colar Pérolas', closure: 'Com Dobradiça', tagline: 'Caixa madeira longa forrada veludo para colares', intro: 'Uma caixa longa e estreita em madeira maciça com interior forrado veludo, dimensionada para colares de pérolas, choker ou correntes longas. Dobradiças ocultas e fecho magnético snap; ideal para joalheiros e para presentes aniversário ou comemoração.' },

  // === WINE-WHISKY ===
  'bamboo-wine-gift-set': { name: 'Conjunto Presente Vinho Bambu', closure: 'Com Dobradiça', tagline: 'Caixa presente vinho bambu com acessórios incluídos', intro: 'Uma caixa presente vinho em bambu com acessórios incluídos: saca-rolhas, anel anti-gota, bico e tampa. Alojamento para uma garrafa standard 750 ml. Bambu food-grade é a opção eco para presentes corporativos ou comemorações.' },
